mapper.select:
SELECT SEQ_NUM , CONTRACT_NUM , TRGT_YM , TYPE_CD , FN_GET_CODENM('CMN0105', TYPE_CD) AS TYPE_CD_NM , SUB_STAT , FN_GET_CODENM('MSP0003', SUB_STAT) AS SUB_STAT_NM , OPEN_DT , TMNT_DT , NAME , MOBILE_NO , EMAIL , DECODE(RESULT_YN, 'Y', '전송', '미전송') AS RESULT_YN , REGST_ID , TO_CHAR(REGST_DTTM, 'YYYYMMDD') AS REGST_DTTM , RVISN_ID , NVL(FN_GET_USRNM(RVISN_ID), 'SYSTEM') AS RVISN_NM , TO_CHAR(RVISN_DTTM, 'YYYYMMDD') AS RVISN_DTTM , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0236' AND CD_VAL = SEND_RSN_CD) AS SEND_RSN , DECODE(SEND_YN, 'Y', '처리', '미처리') AS SEND_YN FROM CMN_TERMS_SMS_SEND_MST WHERE TRGT_YM = #{trgtYm}
AND NAME LIKE #{name} || '%'
AND TYPE_CD = #{typeCd}
AND SEND_YN = #{sendYn}
AND SEND_RSN_CD = #{sendRsn} || ' '
ORDER BY CONTRACT_NUM

mapper.update:
UPDATE 
	CMN_TERMS_SEND_MST
SET
	 RESULT_YN = #{resultYn}
	, RVISN_ID = #{sessionUserId}
	, RVISN_DTTM = SYSDATE
WHERE SEQ_NUM = #{seqNum}

